import{_ as t,o as i,c as e,a2 as l}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"F11: 處分重大資產與資本配置 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6257_矽格/20260430/F11_處分重大資產與資本配置_投資研究員.md","filePath":"審計報告庫/財務審計/6257_矽格/20260430/F11_處分重大資產與資本配置_投資研究員.md"}'),r={name:"審計報告庫/財務審計/6257_矽格/20260430/F11_處分重大資產與資本配置_投資研究員.md"};function n(o,a,s,c,h,_){return i(),e("div",null,[...a[0]||(a[0]=[l('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f11-處分重大資產與資本配置-投資研究員-審計報告" tabindex="-1">F11: 處分重大資產與資本配置 - 投資研究員 審計報告 <a class="header-anchor" href="#f11-處分重大資產與資本配置-投資研究員-審計報告" aria-label="Permalink to &quot;F11: 處分重大資產與資本配置 - 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在處分重大資產（如土地、專利、子公司）之行為？處分損益佔比為何？資金用途是投入再投資還是為了彌補虧損？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：處分PP&amp;E利益僅佔淨利2.7%，逐年遞減；本業營利率由13.4%攀升至20.3%，獲利純度「純淨」。</li><li><strong>風險評級</strong>：低</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>營業利益率20.3%（連續三年階梯成長）；處分PP&amp;E佔淨利僅2.7%</li><li>資本支出：2025年PP&amp;E取得5,311,235仟元</li></ul></li><li><strong>診斷見解</strong>：獲利成長完全來自本業，處分利益佔比已壓縮至可忽略。公司處於「資本密集擴張期」，非「祖產變賣補坑」。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="獲利含金量穿透-earnings-purity" tabindex="-1">獲利含金量穿透 (Earnings Purity) <a class="header-anchor" href="#獲利含金量穿透-earnings-purity" aria-label="Permalink to &quot;獲利含金量穿透 (Earnings Purity)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025年本業營業利益3,967,552仟元 &gt; 本期淨利，本業貢獻超過淨利總額。扣除處分利益後實質淨利較2024年成長2.2%，獲利不含處分灌水。</li><li><strong>深度見解</strong>：欣銓處分利益285,219仟元屬FVOCI工具，直接轉入保留盈餘。</li></ul><h3 id="戰略意圖判別-strategic-intent" tabindex="-1">戰略意圖判別 (Strategic Intent) <a class="header-anchor" href="#戰略意圖判別-strategic-intent" aria-label="Permalink to &quot;戰略意圖判別 (Strategic Intent)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：處分資金明確投入再投資。2025年PP&amp;E取得金額為處分現金流入20.6倍；2026年資本支出預算59.3億元，用於湖口二廠及AI/矽光子測試機台。</li><li><strong>深度見解</strong>：欣銓持股處分目的為活絡資金轉投核心測試業務，公司主動從手機晶片轉型AI/HPC/矽光子。</li></ul><h3 id="資產結構變動-asset-efficiency" tabindex="-1">資產結構變動 (Asset Efficiency) <a class="header-anchor" href="#資產結構變動-asset-efficiency" aria-label="Permalink to &quot;資產結構變動 (Asset Efficiency)&quot;">​</a></h3><ul><li><strong>核心重點</strong>：總資產由2023年增至2025年（+14.7%），PP&amp;E佔比由41.2%降至39.1%。ROE由10.9%升至13.9%，資產效率持續改善。</li><li><strong>深度見解</strong>：處分現金回流遠低於新增投入，資產基礎擴大但效率同步提升。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：2025年業外淨額轉負（74,216仟元），主要受匯率波動及金融資產評價影響。若2026年全球利率環境快速反轉，利息收入（2025年尚未完整披露）可能顯著萎縮，壓縮淨利成長空間。此外，2025年處分欣銓股票的利益285,219仟元已一次性入帳保留盈餘，未來若無同等規模資產可活化，股利政策可能面臨壓力。</li><li><strong>空頭風險二</strong>：2026年資本支出59.3億元為歷史新高，若AI/HPC測試需求不如預期，或湖口二廠、中興三廠投產時程延宕，高額折舊費用將侵蝕營業利益率。目前營業利益率20.3%已處歷史高位，維持此水準的難度隨規模擴大而上升。需關注2026年Q2起資本支出是否追加及實際產能利用率。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: 失敗（financial alias回傳No data），改用年報PDF直接提取</li><li><strong>yfinance</strong>: 未獨立驗證（以年報為主）</li><li><strong>年報/法說</strong>: OK — 2023/2024/2025年報合併報表（Page 10-16, 33, 50-55, 79-80）</li><li><strong>關鍵核對碼</strong>： <ul><li>2025營業利益3,967,552仟元（P.12）、淨利3,330,373仟元（P.12）</li><li>2025處分PP&amp;E利益90,288仟元（P.50 Note 6(20)）</li><li>2025處分PP&amp;E現金流入257,809仟元（P.16）</li><li>2025欣銓FVOCI處分1,752,026仟元、利益285,219仟元（P.33）</li><li>2024營業利益3,074,024仟元（P.12）、業外淨額833,619仟元（P.12）</li><li>2023營業利益2,078,205仟元（P.12）、清算孫公司利益31,394仟元（P.51）</li></ul></li></ul>',19)])])}const g=t(r,[["render",n]]);export{d as __pageData,g as default};
